import{_ as a,o as s,c as i,ae as t}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"devices","description":"`openclaw devices`에 대한 CLI 참조 (장치 페어링 + 토큰 순환/취소)","frontmatter":{"title":"devices","description":"`openclaw devices`에 대한 CLI 참조 (장치 페어링 + 토큰 순환/취소)"},"headers":[],"relativePath":"cli/devices.md","filePath":"cli/devices.md","lastUpdated":null}'),l={name:"cli/devices.md"};function p(o,e,d,n,c,h){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="openclaw-devices" tabindex="-1"><code>openclaw devices</code> <a class="header-anchor" href="#openclaw-devices" aria-label="Permalink to &quot;`openclaw devices`&quot;">​</a></h1><p>장치 페어링 요청과 장치 범위 토큰을 관리합니다.</p><h2 id="명령" tabindex="-1">명령 <a class="header-anchor" href="#명령" aria-label="Permalink to &quot;명령&quot;">​</a></h2><h3 id="openclaw-devices-list" tabindex="-1"><code>openclaw devices list</code> <a class="header-anchor" href="#openclaw-devices-list" aria-label="Permalink to &quot;`openclaw devices list`&quot;">​</a></h3><p>대기 중인 페어링 요청과 페어링된 장치를 나열합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices list</span></span>\n<span class="line"><span>openclaw devices list --json</span></span></code></pre></div><p>대기 중인 요청 출력에는 승인 전에 요청된 역할과 범위가 포함되어 있어 검토할 수 있습니다.</p><h3 id="openclaw-devices-remove-lt-deviceid-gt" tabindex="-1"><code>openclaw devices remove &amp;lt;deviceId&amp;gt;</code> <a class="header-anchor" href="#openclaw-devices-remove-lt-deviceid-gt" aria-label="Permalink to &quot;`openclaw devices remove &amp;lt;deviceId&amp;gt;`&quot;">​</a></h3><p>하나의 페어링된 장치 항목을 제거합니다.</p><p>페어링된 장치 토큰으로 인증할 때 비관리자 호출자는 <strong>자신의</strong> 장치 항목만 제거할 수 있습니다. 다른 장치를 제거하려면 <code>operator.admin</code>이 필요합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices remove &amp;lt;deviceId&amp;gt;</span></span>\n<span class="line"><span>openclaw devices remove &amp;lt;deviceId&amp;gt; --json</span></span></code></pre></div><h3 id="openclaw-devices-clear-yes-pending" tabindex="-1"><code>openclaw devices clear --yes [--pending]</code> <a class="header-anchor" href="#openclaw-devices-clear-yes-pending" aria-label="Permalink to &quot;`openclaw devices clear --yes [--pending]`&quot;">​</a></h3><p>페어링된 장치를 일괄 삭제합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices clear --yes</span></span>\n<span class="line"><span>openclaw devices clear --yes --pending</span></span>\n<span class="line"><span>openclaw devices clear --yes --pending --json</span></span></code></pre></div><h3 id="openclaw-devices-approve-requestid-latest" tabindex="-1"><code>openclaw devices approve [requestId] [--latest]</code> <a class="header-anchor" href="#openclaw-devices-approve-requestid-latest" aria-label="Permalink to &quot;`openclaw devices approve [requestId] [--latest]`&quot;">​</a></h3><p>대기 중인 장치 페어링 요청을 승인합니다. <code>requestId</code>가 생략되면 OpenClaw는 자동으로 가장 최근 대기 중인 요청을 승인합니다.</p><p>참고: 장치가 변경된 인증 세부사항 (역할/범위/공개 키)으로 페어링을 재시도하면 OpenClaw는 이전 대기 항목을 대체하고 새 <code>requestId</code>를 발급합니다. 승인하기 직전에 <code>openclaw devices list</code>를 실행하여 현재 ID를 사용하세요.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices approve</span></span>\n<span class="line"><span>openclaw devices approve &amp;lt;requestId&amp;gt;</span></span>\n<span class="line"><span>openclaw devices approve --latest</span></span></code></pre></div><h3 id="openclaw-devices-reject-lt-requestid-gt" tabindex="-1"><code>openclaw devices reject &amp;lt;requestId&amp;gt;</code> <a class="header-anchor" href="#openclaw-devices-reject-lt-requestid-gt" aria-label="Permalink to &quot;`openclaw devices reject &amp;lt;requestId&amp;gt;`&quot;">​</a></h3><p>대기 중인 장치 페어링 요청을 거부합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices reject &amp;lt;requestId&amp;gt;</span></span></code></pre></div><h3 id="openclaw-devices-rotate-device-lt-id-gt-role-lt-role-gt-scope-lt-scope-gt" tabindex="-1"><code>openclaw devices rotate --device &amp;lt;id&amp;gt; --role &amp;lt;role&amp;gt; [--scope &amp;lt;scope...&amp;gt;]</code> <a class="header-anchor" href="#openclaw-devices-rotate-device-lt-id-gt-role-lt-role-gt-scope-lt-scope-gt" aria-label="Permalink to &quot;`openclaw devices rotate --device &amp;lt;id&amp;gt; --role &amp;lt;role&amp;gt; [--scope &amp;lt;scope...&amp;gt;]`&quot;">​</a></h3><p>특정 역할에 대한 장치 토큰을 순환합니다 (선택적으로 범위 업데이트). 대상 역할은 해당 장치의 승인된 페어링 계약에 이미 존재해야 합니다. 순환은 새로운 미승인 역할을 생성할 수 없습니다. <code>--scope</code>를 생략하면 나중에 저장된 순환 토큰으로 재연결할 때 해당 토큰의 캐시된 승인 범위를 재사용합니다. 명시적 <code>--scope</code> 값을 전달하면 향후 캐시 토큰 재연결에 대해 저장된 범위 세트가 됩니다. 비관리자 페어링 장치 호출자는 <strong>자신의</strong> 장치 토큰만 순환할 수 있습니다. 또한 명시적 <code>--scope</code> 값은 호출자 세션의 자체 운영자 범위 내에 있어야 합니다. 순환은 호출자가 이미 가진 것보다 더 넓은 운영자 토큰을 생성할 수 없습니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices rotate --device &amp;lt;deviceId&amp;gt; --role operator --scope operator.read --scope operator.write</span></span></code></pre></div><p>새 토큰 페이로드를 JSON으로 반환합니다.</p><h3 id="openclaw-devices-revoke-device-lt-id-gt-role-lt-role-gt" tabindex="-1"><code>openclaw devices revoke --device &amp;lt;id&amp;gt; --role &amp;lt;role&amp;gt;</code> <a class="header-anchor" href="#openclaw-devices-revoke-device-lt-id-gt-role-lt-role-gt" aria-label="Permalink to &quot;`openclaw devices revoke --device &amp;lt;id&amp;gt; --role &amp;lt;role&amp;gt;`&quot;">​</a></h3><p>특정 역할에 대한 장치 토큰을 취소합니다.</p><p>비관리자 페어링 장치 호출자는 <strong>자신의</strong> 장치 토큰만 취소할 수 있습니다. 다른 장치의 토큰을 취소하려면 <code>operator.admin</code>이 필요합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw devices revoke --device &amp;lt;deviceId&amp;gt; --role node</span></span></code></pre></div><p>취소 결과를 JSON으로 반환합니다.</p><h2 id="일반-옵션" tabindex="-1">일반 옵션 <a class="header-anchor" href="#일반-옵션" aria-label="Permalink to &quot;일반 옵션&quot;">​</a></h2><ul><li><code>--url &amp;lt;url&amp;gt;</code>: Gateway WebSocket URL (구성된 경우 <code>gateway.remote.url</code>로 기본 설정).</li><li><code>--token &amp;lt;token&amp;gt;</code>: Gateway 토큰 (필요한 경우).</li><li><code>--password &amp;lt;password&amp;gt;</code>: Gateway 비밀번호 (비밀번호 인증).</li><li><code>--timeout &amp;lt;ms&amp;gt;</code>: RPC 타임아웃.</li><li><code>--json</code>: JSON 출력 (스크립팅에 권장).</li></ul><p>참고: <code>--url</code>을 설정하면 CLI는 구성 또는 환경 자격 증명으로 폴백하지 않습니다. <code>--token</code> 또는 <code>--password</code>를 명시적으로 전달하세요. 명시적 자격 증명 누락은 오류입니다.</p><h2 id="참고사항" tabindex="-1">참고사항 <a class="header-anchor" href="#참고사항" aria-label="Permalink to &quot;참고사항&quot;">​</a></h2><ul><li>토큰 순환은 새 토큰을 반환합니다 (민감함). 비밀처럼 취급하세요.</li><li>이 명령은 <code>operator.pairing</code> (또는 <code>operator.admin</code>) 범위가 필요합니다.</li><li>토큰 순환은 해당 장치에 대한 승인된 페어링 역할 세트와 승인된 범위 기준 내에 유지됩니다. 잘못된 캐시 토큰 항목은 새 순환 대상을 부여하지 않습니다.</li><li>페어링 장치 토큰 세션의 경우 교차 장치 관리는 관리자 전용입니다: 호출자에게 <code>operator.admin</code>이 없으면 <code>remove</code>, <code>rotate</code>, <code>revoke</code>는 자기 전용입니다.</li><li><code>devices clear</code>는 의도적으로 <code>--yes</code>로 차단됩니다.</li><li>로컬 루프백에서 페어링 범위를 사용할 수 없는 경우 (명시적 <code>--url</code>이 전달되지 않은 경우) list/approve는 로컬 페어링 폴백을 사용할 수 있습니다.</li><li><code>devices approve</code>는 <code>requestId</code>를 생략하거나 <code>--latest</code>를 전달할 때 자동으로 가장 최신 대기 중인 요청을 선택합니다.</li></ul><h2 id="토큰-드리프트-복구-체크리스트" tabindex="-1">토큰 드리프트 복구 체크리스트 <a class="header-anchor" href="#토큰-드리프트-복구-체크리스트" aria-label="Permalink to &quot;토큰 드리프트 복구 체크리스트&quot;">​</a></h2><p>Control UI 또는 다른 클라이언트가 <code>AUTH_TOKEN_MISMATCH</code> 또는 <code>AUTH_DEVICE_TOKEN_MISMATCH</code>로 계속 실패하는 경우 사용하세요.</p><ol><li>현재 게이트웨이 토큰 소스 확인:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway.auth.token</span></span></code></pre></div><ol start="2"><li>페어링된 장치 나열 및 영향받은 장치 id 식별:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><ol start="3"><li>영향받은 장치의 운영자 토큰 순환:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rotate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --device</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deviceId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--role</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> operator</span></span></code></pre></div><ol start="4"><li>순환으로 충분하지 않은 경우 오래된 페어링을 제거하고 다시 승인:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deviceId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><ol start="5"><li>현재 공유 토큰/비밀번호로 클라이언트 연결 재시도.</li></ol><p>참고사항:</p><ul><li>일반 재연결 인증 우선순위는 명시적 공유 토큰/비밀번호 우선, 그 다음 명시적 <code>deviceToken</code>, 그 다음 저장된 장치 토큰, 그 다음 부트스트랩 토큰입니다.</li><li>신뢰할 수 있는 <code>AUTH_TOKEN_MISMATCH</code> 복구는 한 번의 제한된 재시도를 위해 공유 토큰과 저장된 장치 토큰을 함께 임시로 전송할 수 있습니다.</li></ul><p>관련:</p><ul><li><a href="/openclaw-docs-ko/web/dashboard#if-you-see-unauthorized-1008">대시보드 인증 문제 해결</a></li><li><a href="/openclaw-docs-ko/gateway/troubleshooting#dashboard-control-ui-connectivity">Gateway 문제 해결</a></li></ul>',50)])])}const g=a(l,[["render",p]]);export{k as __pageData,g as default};
